def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.85:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.6 < ratio <= 0.85:
            score = np.exp(-(ratio * 12)) + 0.2
        elif 0.3 < ratio <= 0.6:
            for k in range(1, 8):
                sign = (-1) ** (k+1)
                score += sign * (ratio ** (k + 2)) / (k * 2)
            score = abs(score) + 0.07
        else:
            val = 0.0
            for p in range(1, 4):
                for q in range(1, 4):
                    val += ((-1) ** (p+q)) * (ratio ** (p*q)) / (p+q)
            score = abs(val) + 0.1
        neighbors_influence = 0.0
        for offset in range(1, 6):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    neighbors_influence += diff_ratio * weight * 0.1
        extra_factor = 0.0
        for j in range(n):
            if j == i:
                continue
            dist = abs(i - j)
            cap_j = bins[j]
            if cap_j <= 0:
                continue
            comp_ratio = min(capacity, cap_j) / max(capacity, cap_j)
            if comp_ratio > 0.9:
                extra_factor += np.sqrt(cap_j) / (dist + 1)
            else:
                for m in range(1, 3):
                    extra_factor += (comp_ratio ** m) / ((dist + m) ** 2)
        capacity_factor = np.power(capacity, 1/3)
        if capacity_factor == 0:
            capacity_factor = 1
        priority = score + (neighbors_influence + extra_factor * 0.05) / capacity_factor
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    return priorities
